import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  content: string;
  createdAt: string;
};

// In-memory store — simulates a database for this demo.
// In a real app this would be a database call.
let posts: Post[] = [
  {
    id: '1',
    title: 'First Post',
    content: 'Welcome to the blog!',
    createdAt: new Date('2026-07-14T08:00:00.000Z').toISOString(),
  },
];

/** Internal: pushes a new post to the store (no cache side-effects). */
export function addPost(post: Post): void {
  posts.push(post);
}

/** Internal: replace the store (used to reset state between test runs if needed). */
export function resetPosts(seed?: Post[]): void {
  posts = seed ?? [
    {
      id: '1',
      title: 'First Post',
      content: 'Welcome to the blog!',
      createdAt: new Date('2026-07-14T08:00:00.000Z').toISOString(),
    },
  ];
}

/**
 * Fetch all posts, newest first, cached under the `"posts"` cache tag.
 *
 * Because this function is wrapped with `unstable_cache` and tagged with
 * `["posts"]`, calling `revalidateTag("posts")` in a Server Action will
 * invalidate this cache entry. The very next render of any page that
 * calls `getPosts()` will wait for fresh data — no stale content is served.
 */
export const getPosts = unstable_cache(
  async (): Promise<Post[]> => {
    // In a real app this would be a database query.
    return [...posts].reverse();
  },
  ['posts-list'],
  { tags: ['posts'] },
);

'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/app/lib/posts';

export type CreatePostState = {
  error?: string;
  success?: boolean;
};

export async function createPost(
  prevState: CreatePostState,
  formData: FormData,
): Promise<CreatePostState> {
  const title = formData.get('title')?.toString().trim();
  const content = formData.get('content')?.toString().trim();

  // --- Validation ---
  if (!title) {
    return { error: 'Title is required.' };
  }
  if (title.length > 100) {
    return { error: 'Title must be under 100 characters.' };
  }
  if (!content) {
    return { error: 'Content is required.' };
  }

  // --- Create the post ---
  addPost({
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: new Date().toISOString(),
  });

  // --- Invalidate the "posts" cache tag ---
  // revalidateTag marks every cached entry tagged with "posts" as stale.
  // The next server-side render that calls getPosts() will block on fetching
  // fresh data rather than serving a stale cached copy.
  revalidateTag('posts');

  // --- Redirect to the posts list ---
  // Using redirect() here causes a full server-side render of /posts after
  // cache invalidation, so the user always sees the brand-new post immediately.
  redirect('/posts');
}

import Link from 'next/link';
import { getPosts } from '@/app/lib/posts';

export default async function PostsPage() {
  // getPosts() reads from the unstable_cache store tagged with "posts".
  // The data is fetched server-side and cached until revalidateTag("posts") is called.
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: '2rem 1rem' }}>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '2rem',
        }}
      >
        <h1 style={{ margin: 0 }}>Posts</h1>
        <Link href="/">Create a Post</Link>
      </div>

      {posts.length === 0 ? (
        <p>No posts yet. Create one!</p>
      ) : (
        <ul style={{ listStyle: 'none', padding: 0, display: 'flex', flexDirection: 'column', gap: '1rem' }}>
          {posts.map((post) => (
            <li
              key={post.id}
              style={{
                border: '1px solid #e5e7eb',
                borderRadius: 8,
                padding: '1rem 1.25rem',
              }}
            >
              <h2 style={{ margin: '0 0 0.35rem' }}>{post.title}</h2>
              <p style={{ margin: '0 0 0.5rem', color: '#374151' }}>{post.content}</p>
              <small style={{ color: '#9ca3af' }}>
                {new Date(post.createdAt).toLocaleDateString('en-US', {
                  year: 'numeric',
                  month: 'long',
                  day: 'numeric',
                  hour: '2-digit',
                  minute: '2-digit',
                })}
              </small>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}

'use client';

import { useActionState } from 'react';
import { createPost, type CreatePostState } from '@/app/actions';

export default function Home() {
  const [state, formAction, pending] = useActionState<CreatePostState, FormData>(
    createPost,
    {},
  );

  return (
    <main style={{ maxWidth: 480, margin: '0 auto', padding: '2rem 1rem' }}>
      <h1 style={{ marginBottom: '0.25rem' }}>Create a Post</h1>
      <p style={{ marginBottom: '1.5rem', color: '#6b7280' }}>
        Fill in the fields below and submit. After creation you&apos;ll be
        redirected to the posts list, which always shows fresh data thanks to
        cache-tag invalidation.
      </p>

      <form action={formAction} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
        <div>
          <label htmlFor="title" style={{ display: 'block', marginBottom: '0.25rem', fontWeight: 500 }}>
            Title
          </label>
          <input
            id="title"
            name="title"
            required
            maxLength={100}
            disabled={pending}
            style={{
              width: '100%',
              padding: '0.5rem 0.75rem',
              border: '1px solid #d1d5db',
              borderRadius: 6,
              boxSizing: 'border-box',
            }}
          />
        </div>

        <div>
          <label htmlFor="content" style={{ display: 'block', marginBottom: '0.25rem', fontWeight: 500 }}>
            Content
          </label>
          <textarea
            id="content"
            name="content"
            required
            rows={4}
            disabled={pending}
            style={{
              width: '100%',
              padding: '0.5rem 0.75rem',
              border: '1px solid #d1d5db',
              borderRadius: 6,
              resize: 'vertical',
              boxSizing: 'border-box',
            }}
          />
        </div>

        {state?.error && (
          <p style={{ color: '#dc2626', margin: 0, fontSize: '0.875rem' }}>{state.error}</p>
        )}

        <button
          type="submit"
          disabled={pending}
          style={{
            padding: '0.6rem 1.25rem',
            backgroundColor: pending ? '#9ca3af' : '#2563eb',
            color: '#fff',
            border: 'none',
            borderRadius: 6,
            fontWeight: 600,
            cursor: pending ? 'not-allowed' : 'pointer',
          }}
        >
          {pending ? 'Creating…' : 'Create Post'}
        </button>
      </form>
    </main>
  );
}

